import { Button, ModalR } from '../../../common';
import { useState } from 'react';
import cls from './WorkflowTemplatesModal.module.scss';
import { connect, useDispatch } from 'react-redux';
import { createProcessTemplate } from '../../../../services/processes.service';
import { setMessageBar, setSelectedProcess } from '../../../../reduxStore/actions/flowActions';
import { store } from '../../../../reduxStore/store';

import { first } from 'rxjs';
import { useNavigate } from 'react-router-dom';
import ProcessStepsChart from './ProcessStepsChart';
import { TheProcessContext } from '../../../../context/processStep.context';

const WorkflowTemplatesModal = props => {
	const { isOpen, shadowedContainerStyle, onCreateBlank, gotoProcess, workflowTemplates, gotoComponents } = props;
	const [loading, setLoading] = useState(false);
	const [selectedProcess, setProcess] = useState({ name: '', steps: [] });

	const dispatch = useDispatch();
	document.title = 'New Workflow';

	const navigate = useNavigate();

	const renderWorkflows = () => {
		return workflowTemplates?.map((process, index) => (
			<div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%', minWidth: '260px' }} key={index}>
				<p className={cls.trialTitle}>{`Templates`}</p>
				<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
				<div className={cls.header}>
					<p className={cls.trialText}>{`${process.name}`}</p>
					{!loading && <Button
						disabled={loading}
						title={selectedProcess?.name === process.name ? 'Create' : `View`}
						style={{ backgroundColor: selectedProcess?.name === process.name ? 'green' : 'rgb(83, 159, 234)', width: '80px', minWidth: '80px' }}
						clicked={() => {
							if (selectedProcess?.name !== process.name) {
								setProcess(process);
								dispatch(setSelectedProcess(process));
							} else {
								setLoading(true);
								createProcessTemplate(selectedProcess)
									.pipe(first())
									.subscribe({
										next: data => {
											setLoading(false);
											gotoProcess(data);
										},
										error: error => {
											setLoading(false);
										},
									});
							}
						}}
					/>}
				</div>
				<br />
				<br />
				<p className={cls.subTitle}>{`${process.description}`}</p>
			</div>
		));
	};

	const blankWorkflow = () => {
		return (
			<div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%', minWidth: '260px' }}>
				<p className={cls.trialTitle}>{`New`}</p>
				<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
				<div className={cls.header}>
					<p className={cls.trialText}>{`Blank Workflow`}</p>
					<Button
						disabled={loading}
						title={`Open`}
						style={{ width: '80px', minWidth: '80px' }}
						clicked={() => {
							onCreateBlank();
						}}
					/>
				</div>
				<br />
				<br />
				<p className={cls.subTitle}>{`Create your workflow using a blank canvass`}</p>
			</div>
		);
	};
	const createComponents = () => {
		return (
			<div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%', minWidth: '260px' }}>
				<p className={cls.trialTitle}>{`Components`}</p>
				<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
				<div className={cls.header}>
					<p className={cls.trialText}>{`Create Components`}</p>
					<Button
						disabled={loading}
						title={`Open`}
						style={{ width: '80px', minWidth: '80px' }}
						clicked={() => {
							gotoComponents();
						}}
					/>
				</div>
				<br />
				<br />
				<p className={cls.subTitle}>{`Components are objects that workflows use to input or output informations. In forms they are usally called fields.`}</p>
			</div>
		);
	};
	return (
		<TheProcessContext>
			<ModalR isOpen={isOpen} blured={false} scrollable={true} shadowedContainerStyle={shadowedContainerStyle}>
				<div className={cls.host}>
					<div style={{ display: 'flex', alignItems: 'center' }}>
						<p className={cls.title}>{'New Workflow'}</p>
						<Button clear loading={loading} />
					</div>
					<p className={cls.subtitle}>{'Start a new workflow or select from any of our predefined templates'}</p>
					<div style={{ display: selectedProcess?.name === '' ? 'none' : loading ? 'none' : '', width: '100%' }}>
						<div style={{ display: 'flex', justifyContent: 'space-between', padding: '0 30px 0 30px' }}>
							<Button
								title={'Hide'}
								light
								//style={{ width: '50px', minWidth: '50px' }}
								clicked={() => {
									setProcess({ name: '' });
									setLoading(false);
									dispatch(setSelectedProcess({ name: '', steps: [] }));
								}}
							/>
							<Button
								title={'Create'}
								light
								style={{ color: 'white', backgroundColor: 'green' }}
								clicked={() => {
									setLoading(true);
									createProcessTemplate(selectedProcess)
										.pipe(first())
										.subscribe({
											next: data => {
												setLoading(false);
												gotoProcess(data);
											},
											error: error => {
												setLoading(false);
											},
										});
								}}
							/>
						</div>
						<ProcessStepsChart />
					</div>

					{blankWorkflow()}
					{renderWorkflows()}
					{createComponents()}
				</div>
				<div className={cls.controls}>
					<Button
						disabled={loading}
						loading={loading}
						title={'Close'}
						clicked={() => {
							dispatch(setSelectedProcess(undefined));
							store.dispatch(setMessageBar({ show: false, message: '' }));
							navigate('/');
						}}
					/>
				</div>
			</ModalR>
		</TheProcessContext>
	);
};

const mapStateToProps = store => {
	const { companyProcesses, companyPositionsArray, allModules, components, onBoardingCompleted, workflowTemplates } = store.flowReducer;
	return { companyProcesses, companyPositionsArray, allModules, components, onBoardingCompleted, workflowTemplates };
};

export default connect(mapStateToProps)(WorkflowTemplatesModal);
